class _DashedBorder extends CustomPainter {
  @override
  void paint(Canvas canvas, Size size) {
    final paint = Paint()
      ..color = Colors.white12
      ..strokeWidth = 1.5
      ..style = PaintingStyle.stroke;

    const dash = 8.0;
    const gap = 6.0;

    for (double x = 0; x < size.width; x += dash + gap) {
      canvas.drawLine(
          Offset(x, 0), Offset((x + dash).clamp(0, size.width), 0), paint);
      canvas.drawLine(Offset(x, size.height),
          Offset((x + dash).clamp(0, size.width), size.height), paint);
    }
    for (double y = 0; y < size.height; y += dash + gap) {
      canvas.drawLine(
          Offset(0, y), Offset(0, (y + dash).clamp(0, size.height)), paint);
      canvas.drawLine(Offset(size.width, y),
          Offset(size.width, (y + dash).clamp(0, size.height)), paint);
    }
  }

  @override
  bool shouldRepaint(_) => false;
}

